var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"크윽……! 쿨럭……!","JPN":"くうっ……！　ゲホッ……！","ENG":"Krrgh...! *Cough...!*","TWN":"咳咳……！咳咳……！"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"우리가 싸우는 동안…… 애를 만신창이로 만들어 놓은 거야?","JPN":"私たちが戦ってる間に……子どもを傷つけたのか？","ENG":"While we were fighting... You beat her to a pulp?!","TWN":"你趁我們交手時……把她弄得渾身是傷嗎？"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"아, 말을 안 들어서요. 이건 제가 저로 완성되기 위한 <color=#ffd34c>제 거</color>니까.","JPN":"あ、言うことを聞かなくって。これは私が私として完成するための<color=#ffd34c>部品</color>ですから。","ENG":"Oh, this is because she wouldn't listen to me. You see, she is <color=#ffd34c>mine</color> so that I can be whole.","TWN":"誰叫她不聽話，這是我要拿來完成我的<color=#ffd34c>東西</color>。"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"그럼 언니는 잠깐 쉬고 있어요. 저 경찰은 내가 마저 혼내 줄게.","JPN":"じゃあ、ユリさんはちょっと休んでください。あの警察官は私がこらしめてあげますよ。","ENG":"Anyway Yuri, how about you take a little rest. I'll give that cop a beating for you.","TWN":"那姊姊你先休息一下，我去教訓一下那個警察。"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이런, 공범이 아직…… 아윽……","JPN":"まずい、共犯者がまだ……うぅっ……","ENG":"Damm, I didn't realize… an accomplice... Ngh...","TWN":"可惡，還有共犯……呃……"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"에헷. 언니에게 칼 겨눴으니까 사냥당해도 어쩔 수 없겠네? 그치?","JPN":"えへっ。ユリさんに刃を向けたんだから、狩られても仕方ないよね？　そうでしょ？","ENG":"Hehe. Since you pointed your sword at her, you don't really have a choice but to get hunted, right?","TWN":"嘿嘿，你敢拿刀對準姊姊，那我只好進行狩獵囉？對吧？"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……그만둬.","JPN":"……やめろ。","ENG":"...Stop it.","TWN":"……住手。"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"으응~?","JPN":"ううん～？","ENG":"Hmm?","TWN":"嗯～？"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"유리 언니, 상한 우유라도 마셨어요? 저 애 언니를 죽이려고 했잖아요?","JPN":"ユリさん、腐った牛乳でも飲んじゃったんですか？　あの子、ユリさんを殺そうとしたんですよ？","ENG":"Yuri, did you drink spoiled milk or something? She tried to kill you!","TWN":"悠麗姊姊，你是喝到過期的牛奶嗎？她想殺死你欸？"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"죽이려고 한 적 없어. 체포하려고 했지.","JPN":"殺そうとしたことはない。逮捕しようとしただけだ。","ENG":"No, she didn't. She was trying to arrest me.","TWN":"她並沒有想殺我，她只是想逮補我而已。"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"오히려……. 지금은 애를 그 지경으로 만든 네가 더 문제라는 생각밖에 안 들어.","JPN":"むしろ……今はあの子をあんな風にしたお前の方が問題だとしか思えない。","ENG":"However... All I can think of now is how wrong it was for you to harm that kid.","TWN":"倒是你……把她打成那樣，我看你比較有問題吧？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"우으~ 대장도 모자라서 언니까지 섭섭하게 그러기예요?","JPN":"うう～隊長にユリさんまで、ひどいです。","ENG":"Boo! Now you're going to talk like Captain to me?","TWN":"嗚嗚～隊長兇我還不夠，連姊姊也要讓我難過嗎？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"애를 내려 놓고 물러서, 레비아. 나도 기껏 생긴 후임에게 이러고 싶지 않아.","JPN":"子どもを下ろして下がれ、レヴィア。私もせっかくできた後輩にこんなことしたくない。","ENG":"Put the kid down and step away, Levia. And you know I don't want to be saying this to you.","TWN":"莉維亞，把她放開後離開。我也不想對好不容易進來的後輩這樣。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"에헷. 기껏 찾은 동생이라고요. 아무리 유리 언니 부탁이라도 들어 드리기 어렵겠는데요.","JPN":"えへっ。せっかく見つけた妹なんですよ。いくらユリさんの頼みでもそれは聞いてあげられそうにないですね。","ENG":"Hehe. But she's my sister! I'm sorry, but I can't do that. Even if it's you who’s asking, Yuri.","TWN":"嘿嘿，我好不容易才找到妹妹的，就算是姊姊的請求，我也無法答應欸？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"자, 그럼 다들 여기서 나가 주실래요? ","JPN":"さてと、じゃあみんなここから出てくれます？ ","ENG":"Now then, will everyone else please leave? ","TWN":"可以請大家離開這裡嗎？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"지금 제 몸이 여기로 넘어오기에는 틈이 너무 좁거든요. 안 본 사이 살쪘나 봐.","JPN":"今、私の身体がこっちに来るには亀裂の幅が狭すぎるんですよ。少し見ない間に太ったみたい。","ENG":"The gap is too narrow for my body to come over here. It seems I gained a little bit of weight since last time.","TWN":"因為裂縫太窄，我的身體過不來，可能是一陣子沒見面有變胖吧？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"그래도 마침 관리국의 장비도 있으니까 이걸 써서 넓히면……","JPN":"でもちょうど管理局の装備もあるから、これを使って広げれば……","ENG":"But at least we have this device from the Administration. So if I use this to expand the space─","TWN":"不過剛好有管理局的裝備，可以用這個拓寬……"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"당한 척 하고 방심시켰던 거야, 동생? 재생력에 잔머리까지 늘었네?","JPN":"やられたふりして気を緩ませる作戦だったの？　再生力も高くなった上に小賢しくなったのね。","ENG":"Did you pretend to have fainted so I would let my guard down, Orca? It seems like your regeneration ability isn't the only thing that's improved.","TWN":"妹妹，你是想讓我鬆懈，才假裝輸給我的是嗎？你的重生能力跟小聰明都進步不少喔。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_HIT_STING_SMALL"},{"id":"L30_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"이 방에서 사장 냄새가 나.","JPN":"この部屋から社長の匂いがする。","ENG":"I smell Boss's scent in this room.","TWN":"這個房間裡有老闆的味道。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"이건 우리 회사 거야. 네 마음대로 만지지 마.","JPN":"これは会社のもの。勝手に触らないで。","ENG":"This is our company. You don't get to touch it.","TWN":"這是我們公司的，你不要亂碰。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"에이, 그렇다고 언니 손목을 베면 어떡해.","JPN":"ええ～だからってお姉さんの手首斬っちゃダメでしょ。","ENG":"Oh, come on. That doesn't mean you get to slit your big sister’s wrist.","TWN":"哎呀，就算是這樣你也不能砍姊姊的手吧？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"너 자꾸 앙탈 부리면 싹둑싹둑해 버린다?","JPN":"あんまり駄々をこねてるとザクザク切り刻んじゃうよ？","ENG":"If you keep up the attitude, I'm going to have to cut you up. Snip snip!","TWN":"你老是不聽話，姊姊會把你喀嚓喀擦喔？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"……상관없어. 여기라면 아까처럼 이리저리 도망치지 못해.","JPN":"……関係ない。ここならさっきみたいにあっちこっち逃げられない。","ENG":"...I don't care. In a small space like this, you won't be able to evade like last time.","TWN":"……無所謂，在這裡，你就沒辦法像剛剛那樣逃掉。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"방금 그 발언은 좌시할 수 없어. 경찰 앞에서 시민을 협박하다니 제정신이야?","JPN":"今のその発言は黙認できないわね。警察官の前で市民を脅すなんて、正気？","ENG":"As an officer of the law, I can't ignore what you just said. Are you out of your mind to really threaten a civilian in front of me?","TWN":"你剛才的發言我不能坐視不理，竟敢在警察面前威脅市民，你腦袋有問題嗎？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"이유미, 부상자 주제에 움직이지 마.","JPN":"カスカベ・ユミ、怪我人のくせに動くな。","ENG":"Major, don't try anything stupid. You're injured.","TWN":"李悠美，你自己也受傷，少輕舉妄動。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"공범 주제에 누구더러 이래라저래라야? 그쪽이나 얌전히 있어.","JPN":"共犯のくせに誰に向かって命令してるの？　そっちこそ大人しくしてなさいよ。","ENG":"Who are you to tell me what to do? You're the one who should stay down, not me.","TWN":"你身為一個共犯，還敢在那大言不慚，給我老實點！"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"언니는…… 이면세계에 같이 갔던 그 경찰?","JPN":"あなたは……一緒に裏世界に行ったあの警察官？","ENG":"Aren't you... the police officer who went to Counterside with me?","TWN":"姊姊……是一起去過異界的那個警察？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"네. 이유미 경정입니다. 오랜만이에요.","JPN":"はい。カスカベ・ユミ警視です。お久しぶりですね。","ENG":"Yes. I’m Major Lee Yumi. Long time no see.","TWN":"沒錯，我是李悠美警正。好久不見。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"경찰 아가씨, 미안한데 이건 가정사라고 해야 할까? 매우 프라이빗한 영역이거든요?","JPN":"悪いけどこれは家庭の事情って言うの？　とてもプライベートな部分なんです。","ENG":"Miss officer? I'm sorry, but this is a family matter, you see? An extremely private affair.","TWN":"警察大人，不好意思，該說這是我們家務事嗎？是私事好嗎？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"이미 만신창인데 괜히 끼어들다가 혼쭐날 걸요.","JPN":"すでに傷だらけなのに、下手に首を突っ込めばどうなっても知りませんよ。","ENG":"You're hurt bad enough already. Getting involved wouldn't be a great idea.","TWN":"你傷得那麼重，再雞婆的話別怪我不客氣喔。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……레비아.","JPN":"……レヴィア。","ENG":"…Levia.","TWN":"……莉維亞。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"유리 언니?","JPN":"ユリさん？","ENG":"Yes, Yuri?","TWN":"悠麗姊姊？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"선임으로서, 네 그 지저분한 손버릇은 언제 하루 날 잡아서 한 번 고쳐 주고 싶었어.","JPN":"先輩として、お前のその悪い手癖はいつか直してあげたかったんだ。","ENG":"As a senior, I've always wanted to fix that nasty habit of yours one day.","TWN":"身為你的前輩，我早就想改改你那沒大沒小的壞習慣。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"갑자기 뭐야? 내분이라도 일어났어?","JPN":"いきなり何なの？　内輪もめ？","ENG":"What's going on? Are you two having some sort of internal conflict?","TWN":"突然是怎麼回事？搞內鬨嗎？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"이쪽도 이쪽대로 룰이 있어. 넌 신경 끄고 네 할일이나 해.","JPN":"こっちもこっちなりのルールがあるんだ。構わず自分の仕事でもしろ。","ENG":"We have our own rules. Mind your own business.","TWN":"我們也有我們自己的規矩，不關你的事，管好你自己吧。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"하! 그 룰이 엉망진창이니까 저런 위험한 인간도 섞여 있는 거겠지!","JPN":"は！　ルールがめちゃくちゃだからあんな危険な人間も混ざってるんでしょ！","ENG":"*Scoff* Some rules they must be to take a dangerous person like her on board!","TWN":"哈！就是因為規矩亂七八糟的，才會讓那種危險人物混進來吧！"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"으음. 어째 공공의 적이 되어 버린 기분인데요.","JPN":"うーん。なんだか共通の敵になってしまった気がするんですけど。","ENG":"Hmm... Why do I feel like I've become the bad guy here?","TWN":"嗯，有種成為全民公敵的感覺。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"뭐, 박대는 익숙하거든요. 관상어랑 곰치가 한 연못에 살면 결말은 뻔하니까.","JPN":"まあ、冷遇には慣れてるんで。観賞魚とウツボが同じ池に住めば、結末は目に見えてるでしょ？","ENG":"Oh well, I'm used to being treated poorly. Plus it's obvious what will happen if you put a shark in a fish tank.","TWN":"反正我很習慣被針對啦。將觀賞魚和海鰻關在一個池裡，結局應該很明顯吧？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"그런데 두 분, 지금 누구랑 싸우려고 하는지 아세요?","JPN":"でも二人とも、今誰と戦おうとしてるのかわかってるんですか？","ENG":"But do either of you even know who you're going up against?","TWN":"不過二位，你們知道對手是誰嗎？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"중범죄자.","JPN":"重犯罪者。","ENG":"A felon.","TWN":"重犯。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"폐급 신입.","JPN":"使えない新人。","ENG":"A trash rookie.","TWN":"留停新人。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"……우웅. 야박하다, 진짜.","JPN":"……うーん。ひどいなあ、もう。","ENG":"Oof... That's mean, seriously.","TWN":"……嗚嗚，真是無情。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"자기 동생이란 애한테 싹둑싹둑 어쩌고 한 순간부터 네 평가는 바닥났어.","JPN":"自分の妹って子にザクザク切り刻むとか言っている時点であなたの評価は最悪よ。","ENG":"You lost any and all respect we had for you when you threatened to cut up and your so-called sister.","TWN":"早在你對所謂的妹妹說什麼喀嚓喀嚓的時候，對你的評價就已經跌落谷底。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"실랑이는 됐으니까 검거에나 협조해.","JPN":"ケンカはいいから逮捕するのに協力しなさい。","ENG":"Will you stop fighting with me and help me arrest her?","TWN":"說完沒有，乖乖接受逮補吧。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"내키진 않지만 정상 참작은 해 줄 테니까.","JPN":"気は乗らないけど情状酌量はしてあげるから。","ENG":"Even though I don’t like it, I'll take your cooperation into account.","TWN":"雖然不太樂意，但我會酌情處理的。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"착각하지 마. 죽는 건 몰라도 잡혀 주겠다고 한 적 없어.","JPN":"勘違いするな。死ぬならともかく、捕まってやると言ったことはない。","ENG":"Hey, don't kid yourself. I never said anything about getting arrested by you.","TWN":"別誤會，我可沒說要乖乖就擒，除非我死掉那還有可能。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"오르카, 괜찮아?","JPN":"オルカ、大丈夫？","ENG":"Orca, are you all right?","TWN":"奧爾卡，你沒事吧？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"아직 참을 수 있다. 그러니 너는……","JPN":"まだ耐えられる。だからお前は……","ENG":"I can still hold it in. So you...","TWN":"我還能忍，所以你……"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"신중하게, 기회를 노려.","JPN":"慎重に、チャンスを狙え。","ENG":"Be careful and look for your opportunity.","TWN":"伺機行動。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"에헷. 졸지에 사냥감이 되어 버렸네. 별 수 없죠.","JPN":"えへっ。いきなり獲物になっちゃった。仕方ないな～","ENG":"Hehe. Looks like I'm the one being hunted now. Oh well.","TWN":"嘿嘿，突然變成我是獵物啦？真傷腦筋。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"하지만 전 그렇게 호락호락한 사냥감이 아니라구요?","JPN":"でも私、そう弱い獲物じゃないんですよ？","ENG":"But just so you know, I won't be hunted so easily!","TWN":"不過我可不是那麼好對付的獵物喔。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};